#define THREADS 256

inline int mirror_idx(int d, int sizeD)
{
    if (sizeD <= 1) return 0;
    if (d >= sizeD) {
        d = 2 * sizeD - 2 - d;
    } else if (d < 0) {
        d = -d;
    }
    if (d < 0) d = 0;
    if (d >= sizeD) d = sizeD - 1;
    return d;
}

inline int h_odd(__global const int *in, int sx, int y, int oddX)
{
    int x = mirror_idx(oddX, sx);
    int xl = mirror_idx(x - 1, sx);
    int xr = mirror_idx(x + 1, sx);
    int c = in[y * sx + x];
    return c - (in[y * sx + xl] + in[y * sx + xr]) / 2;
}

inline int h_even(__global const int *in, int sx, int y, int evenX)
{
    int x = mirror_idx(evenX, sx);
    int d1 = h_odd(in, sx, y, x - 1);
    int d2 = h_odd(in, sx, y, x + 1);
    return in[y * sx + x] + (d1 + d2 + 2) / 4;
}

inline int v_odd(__global const int *tmp, int sx, int sy, int col, int oddY)
{
    int y = mirror_idx(oddY, sy);
    int yu = mirror_idx(y - 1, sy);
    int yd = mirror_idx(y + 1, sy);
    int c = tmp[y * sx + col];
    return c - (tmp[yu * sx + col] + tmp[yd * sx + col]) / 2;
}

inline int v_even(__global const int *tmp, int sx, int sy, int col, int evenY)
{
    int y = mirror_idx(evenY, sy);
    int d1 = v_odd(tmp, sx, sy, col, y - 1);
    int d2 = v_odd(tmp, sx, sy, col, y + 1);
    return tmp[y * sx + col] + (d1 + d2 + 2) / 4;
}

