__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    if (get_global_id(0) != 0 || get_global_id(1) != 0) return;
    if (sizeX <= 0 || sizeY <= 0) return;

    const int sx = sizeX;
    const int sy = sizeY;

    const int llx = (sx + 1) / 2;
    const int hlx = sx - llx;
    const int lly = (sy + 1) / 2;
    const int hly = lly;
    const int lhy = sy - lly;
    const int hhy = lhy;

    const int baseLL = 0;
    const int baseHL = baseLL + llx * lly;
    const int baseLH = baseHL + hlx * hly;
    const int baseHH = baseLH + llx * lhy;

    for (int y = 0; y < sy; y++) {
        for (int i = 0; i < llx; i++) {
            int x = 2 * i;
            output[y * sx + i] = h_even(input, sx, y, x);
        }
        for (int i = 0; i < hlx; i++) {
            int x = 2 * i + 1;
            output[y * sx + llx + i] = h_odd(input, sx, y, x);
        }
    }

    for (int c = 0; c < llx; c++) {
        for (int j = 0; j < lly; j++) {
            int y = 2 * j;
            input[baseLL + j * llx + c] = v_even(output, sx, sy, c, y);
        }
        for (int j = 0; j < hhy; j++) {
            int y = 2 * j + 1;
            input[baseLH + j * llx + c] = v_odd(output, sx, sy, c, y);
        }
    }

    for (int c = 0; c < hlx; c++) {
        int col = llx + c;
        for (int j = 0; j < hly; j++) {
            int y = 2 * j;
            input[baseHL + j * hlx + c] = v_even(output, sx, sy, col, y);
        }
        for (int j = 0; j < hhy; j++) {
            int y = 2 * j + 1;
            input[baseHH + j * hlx + c] = v_odd(output, sx, sy, col, y);
        }
    }

    for (int i = 0; i < sx * sy; i++) {
        output[i] = input[i];
    }
}

